 * 
 * This service enables dynamic calculation of business metrics using JavaScript formulas.
 * It allows business analysts to define and execute custom calculation formulas without
 * requiring application redeployment.
 */
public class DynamicMetricService {

    private static final String SCRIPT_ENGINE_NAME = "JavaScript";
    private static final ScriptEngineManager SCRIPT_ENGINE_MANAGER = new ScriptEngineManager();

    /**
     * Calculates a metric based on the provided formula and context variables.
     *
     * @param formula the mathematical or logical formula as a string (e.g., "(metricA + metricB) * 0.9")
     * @param context a Map containing variable names and their corresponding values required by the formula
     * @return the computed result of the formula evaluation
     * @throws ScriptException if an error occurs during script execution
     * @throws NullPointerException if formula or context is null
     * @throws IllegalArgumentException if formula is empty or context is empty
     */
    public Object calculate(String formula, Map<String, Object> context) throws ScriptException {
        // Validate inputs
        Objects.requireNonNull(formula, "Formula cannot be null");
        Objects.requireNonNull(context, "Context cannot be null");

        if (formula.trim().isEmpty()) {
            throw new IllegalArgumentException("Formula cannot be empty");
        }

        if (context.isEmpty()) {
            throw new IllegalArgumentException("Context cannot be empty");
        }

        // Obtain a JavaScript engine instance
        ScriptEngine scriptEngine = SCRIPT_ENGINE_MANAGER.getEngineByName(SCRIPT_ENGINE_NAME);

        if (scriptEngine == null) {
            throw new RuntimeException("JavaScript engine not found. Ensure Java 8+ is used.");
        }

        // Bind context variables to the script engine
        for (Map.Entry<String, Object> entry : context.entrySet()) {
            scriptEngine.put(entry.getKey(), entry.getValue());
